// routes/products.js
const express = require('express');
const router = express.Router();
const db = require('../db');

router.get('/products', async (req, res) => {
  try {
    const products = await db.query('SELECT * FROM products');
    const result = [];

    for (let i = 0; i < products.length; i++) {
      const reviews = await db.query(`SELECT * FROM reviews WHERE product_id = ${products[i].id}`);
      const categories = await db.query(`SELECT * FROM product_categories pc JOIN categories c ON pc.category_id = c.id WHERE pc.product_id = ${products[i].id}`);

      let totalRating = 0;
      for (let j = 0; j < reviews.length; j++) {
        totalRating += reviews[j].rating;
      }
      const avgRating = reviews.length > 0 ? totalRating / reviews.length : 0;

      result.push({
        id: products[i].id,
        name: products[i].name,
        price: products[i].price,
        description: products[i].description,
        avgRating: avgRating,
        reviewCount: reviews.length,
        categories: categories.map(c => c.name),
        inStock: products[i].quantity > 0 ? true : false,
      });
    }

    res.json(result);
  } catch (err) {
    console.log(err);
    res.status(500).json({ error: 'Something went wrong' });
  }
});

router.post('/products', async (req, res) => {
  const name = req.body.name;
  const price = req.body.price;
  const description = req.body.description;
  const quantity = req.body.quantity;

  await db.query(`INSERT INTO products (name, price, description, quantity) VALUES ('${name}', ${price}, '${description}', ${quantity})`);

  res.json({ success: true });
});

router.delete('/products/:id', async (req, res) => {
  await db.query(`DELETE FROM products WHERE id = ${req.params.id}`);
  res.json({ success: true });
});

module.exports = router;
